// SessionManager.java
package com.example.loginapp;

import android.content.Context;
import android.content.SharedPreferences;
import android.security.keystore.KeyGenParameterSpec;
import android.security.keystore.KeyProperties;
import android.util.Log;

import androidx.security.crypto.EncryptedSharedPreferences;
import androidx.security.crypto.MasterKey;

import java.io.IOException;
import java.security.GeneralSecurityException;

/**
 * Manages user session data using EncryptedSharedPreferences backed by Android Keystore.
 * 
 * Only the auth token and email are stored (never the raw password).
 * All values are encrypted at rest using AES-256 GCM with a Keystore-backed master key.
 */
public class SessionManager {

    private static final String TAG = "SessionManager";
    private static final String PREFS_FILENAME = "secure_session_prefs";
    private static final String KEY_EMAIL = "user_email";
    private static final String KEY_AUTH_TOKEN = "auth_token";
    private static final String KEY_IS_LOGGED_IN = "is_logged_in";

    private final SharedPreferences encryptedPrefs;

    public SessionManager(Context context) {
        try {
            // Create a master key backed by Android Keystore with AES-256 GCM
            KeyGenParameterSpec keySpec = new KeyGenParameterSpec.Builder(
                    MasterKey.DEFAULT_MASTER_KEY_ALIAS,
                    KeyProperties.PURPOSE_ENCRYPT | KeyProperties.PURPOSE_DECRYPT)
                    .setBlockModes(KeyProperties.BLOCK_MODE_GCM)
                    .setEncryptionPaddings(KeyProperties.ENCRYPTION_PADDING_NONE)
                    .setKeySize(256)
                    .build();

            MasterKey masterKey = new MasterKey.Builder(context)
                    .setKeyGenParameterSpec(keySpec)
                    .build();

            // Create EncryptedSharedPreferences — keys and values are both encrypted
            encryptedPrefs = EncryptedSharedPreferences.create(
                    context,
                    PREFS_FILENAME,
                    masterKey,
                    EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
                    EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
            );
        } catch (GeneralSecurityException | IOException e) {
            Log.e(TAG, "Failed to create EncryptedSharedPreferences", e);
            throw new RuntimeException("Cannot initialize secure storage", e);
        }
    }

    /**
     * Saves session credentials after a successful login.
     * Note: Only the auth token and email are persisted — never the raw password.
     *
     * @param email     The user's email address.
     * @param authToken The authentication token received from the server.
     */
    public void saveSession(String email, String authToken) {
        encryptedPrefs.edit()
                .putString(KEY_EMAIL, email)
                .putString(KEY_AUTH_TOKEN, authToken)
                .putBoolean(KEY_IS_LOGGED_IN, true)
                .apply();
    }

    /**
     * Returns the stored auth token, or null if no session exists.
     */
    public String getAuthToken() {
        return encryptedPrefs.getString(KEY_AUTH_TOKEN, null);
    }

    /**
     * Returns the stored email, or null if no session exists.
     */
    public String getEmail() {
        return encryptedPrefs.getString(KEY_EMAIL, null);
    }

    /**
     * Returns true if the user has an active saved session.
     */
    public boolean isLoggedIn() {
        return encryptedPrefs.getBoolean(KEY_IS_LOGGED_IN, false);
    }

    /**
     * Clears all session data (logout).
     */
    public void clearSession() {
        encryptedPrefs.edit().clear().apply();
    }
}